// Prepara parametri con valori di default
const input = $input.all()[0].json;
console.log('input', input);
return [{
  json: {
    repository: input.repository,
    sha: input.sha || "master",
    path: input.path || "",
    author: input.author || "",
    since: input.since || "",
    until: input.until || "",
    per_page: parseInt(input.per_page || "100")
  }
}];

// Formatta lista commit - GESTISCE ANCHE ITEM VUOTI
const items = $input.all();

console.log("=== FORMAT OUTPUT DEBUG ===");
console.log("Items received:", items ? items.length : "null");

// Controlla se ci sono items
if (!items || items.length === 0) {
  console.log("No items received");
  return [{ 
    json: { 
      commits: [], 
      count: 0,
      message: "No data received from HTTP request"
    } 
  }];
}

const firstItem = items[0];
console.log("First item:", firstItem);

// GESTISCE ITEM VUOTO (il caso del tuo screenshot)
if (!firstItem.json || Object.keys(firstItem.json).length === 0) {
  console.log("Item is empty - GitHub returned []");
  return [{ 
    json: { 
      commits: [], 
      count: 0,
      message: "No commits found matching the criteria"
    } 
  }];
}

const data = firstItem.json;
console.log("Data type:", typeof data);
console.log("Is array?", Array.isArray(data));

// Se data è un array vuoto
if (Array.isArray(data) && data.length === 0) {
  console.log("Empty array returned");
  return [{ 
    json: { 
      commits: [], 
      count: 0,
      message: "No commits found matching the criteria"
    } 
  }];
}

// Estrai commits
let commits = [];

// Caso 1: Multiple items (split attivo)
if (items.length > 1) {
  console.log("Multiple items detected");
  commits = items
    .filter(item => item.json && item.json.sha)
    .map(item => item.json);
}
// Caso 2: Single item con array
else if (Array.isArray(data)) {
  console.log("Single item with array of", data.length, "commits");
  commits = data;
}
// Caso 3: Single commit object
else if (data && data.sha) {
  console.log("Single commit object");
  commits = [data];
}

console.log("Total commits to format:", commits.length);

// Se ancora nessun commit
if (commits.length === 0) {
  return [{ 
    json: { 
      commits: [], 
      count: 0,
      message: "No commits found matching the criteria"
    } 
  }];
}

// Formatta ogni commit
const formatted = commits.map(commit => ({
  sha: commit.sha.substring(0, 7),
  full_sha: commit.sha,
  message: commit.commit.message.split('\n')[0],
  full_message: commit.commit.message,
  author: commit.commit.author.name,
  author_email: commit.commit.author.email,
  date: commit.commit.author.date,
  url: commit.html_url,
  committer: commit.commit.committer.name,
  verified: commit.commit.verification?.verified || false
}));

console.log("Formatted", formatted.length, "commits");

return [{ 
  json: { 
    commits: formatted,
    count: formatted.length,
    message: `Found ${formatted.length} commit(s)`
  } 
}];

// Costruisci URL per GitHub API
const params = $input.all()[0].json;

// URL base
let url = `https://api.github.com/repos/${params.repository}/commits`;

// Array di parametri query
const queryParams = [
  `per_page=${params.per_page}`
];

// Aggiungi sha SOLO se specificato dall'utente
if (params.sha && params.sha !== "main" && params.sha !== "master") {
  queryParams.push(`sha=${params.sha}`);
}

// Aggiungi path solo se presente
if (params.path && params.path.trim().length > 0) {
  queryParams.push(`path=${encodeURIComponent(params.path)}`);
}

// Aggiungi author solo se presente
if (params.author && params.author.trim().length > 0) {
  queryParams.push(`author=${encodeURIComponent(params.author)}`);
}

// Aggiungi since solo se presente
if (params.since && params.since.trim().length > 0) {
  queryParams.push(`since=${params.since}`);
}

// Aggiungi until solo se presente
if (params.until && params.until.trim().length > 0) {
  queryParams.push(`until=${params.until}`);
}

// Unisci tutto
url = url + '?' + queryParams.join('&');

return [{
  json: {
    url: url
  }
}];
